const rawText = $input.first().json.Task;

// Заменяем literal \n на реальные переносы строк
const text = rawText.replace(/\\n/g, '\n');

// Определяем формат входных данных
const isNewFormat = text.indexOf('[Название задачи]') !== -1;
const isOldFormat = text.indexOf('Название:') !== -1 && text.indexOf('Тип объекта:') !== -1;

let asset = {
  name: '',
  type: '',
  sections: [],
  colorPalette: [],
  rawText: text
};

if (isNewFormat) {
  // Новый формат с [секциями]
  const sectionRegex = /\[([^\]]+)\]/g;
  const parts = text.split(sectionRegex);

  for (let i = 1; i < parts.length; i += 2) {
    const sectionName = parts[i].trim();
    const sectionContent = (parts[i + 1] || '').trim();

    asset.sections.push({
      name: sectionName,
      content: sectionContent
    });

    // Извлекаем название
    if (sectionName === 'Название задачи') {
      asset.name = sectionContent.split('\n')[0].trim();
    }

    // Извлекаем тип из названия
    if (asset.name.indexOf('Icon_') === 0) {
      asset.type = 'Иконка';
    } else if (asset.name.indexOf('Building_') === 0) {
      asset.type = 'Здание';
    } else {
      asset.type = 'Ассет';
    }
  }

  // Извлекаем цветовую палитру
  const paletteMatch = text.match(/Цветовая палитра:([^[]+)/);
  if (paletteMatch) {
    const paletteText = paletteMatch[1];
    const colorMatches = paletteText.match(/([А-Яа-яA-Za-z-]+)\s*\((#[A-Fa-f0-9]{6})\)\s*[-—]\s*([^\n]+)/g);
    if (colorMatches) {
      colorMatches.forEach(function(match) {
        const parts = match.match(/([А-Яа-яA-Za-z-]+)\s*\((#[A-Fa-f0-9]{6})\)\s*[-—]\s*(.+)/);
        if (parts) {
          asset.colorPalette.push({
            name: parts[1].trim(),
            hex: parts[2],
            usage: parts[3].trim()
          });
        }
      });
    }
  }

} else if (isOldFormat) {
  // Старый формат с "Название:", "Тип объекта:" и т.д.
  let currentSection = '';
  const lines = text.split('\n');

  const sectionMap = {
    'Краткое описание:': 'shortDescription',
    'Роль/назначение:': 'role',
    'Форма и композиция:': 'formAndComposition',
    'Цвет и материалы:': 'colorAndMaterials',
    'Архитектурные детали:': 'architecturalDetails',
    'Функциональные элементы:': 'functionalElements',
    'Ключевые элементы стиля:': 'styleElements',
    'Общая стилистика проекта:': 'generalStyle',
    'Цветовая палитра:': 'colorPalette'
  };

  asset.shortDescription = '';
  asset.role = '';
  asset.formAndComposition = '';
  asset.colorAndMaterials = '';
  asset.architecturalDetails = '';
  asset.functionalElements = '';
  asset.styleElements = '';
  asset.generalStyle = '';

  for (let i = 0; i < lines.length; i++) {
    const trimmed = lines[i].trim();
    if (!trimmed) continue;

    if (trimmed.indexOf('Название:') === 0) {
      asset.name = trimmed.replace('Название:', '').trim();
      currentSection = '';
    } else if (trimmed.indexOf('Тип объекта:') === 0) {
      asset.type = trimmed.replace('Тип объекта:', '').trim();
      currentSection = '';
    } else if (trimmed.indexOf('Описание и адаптация:') === 0) {
      currentSection = '';
    } else {
      // Проверяем секции
      let foundSection = false;
      for (let key in sectionMap) {
        if (trimmed.indexOf(key) === 0) {
          currentSection = sectionMap[key];
          foundSection = true;
          break;
        }
      }

      if (!foundSection && currentSection) {
        if (currentSection === 'colorPalette') {
          const match = trimmed.match(/(.+?)\s*\((#[A-Fa-f0-9]{6})\)\s*используется для\s*(.+)/);
          if (match) {
            asset.colorPalette.push({
              name: match[1].trim(),
              hex: match[2],
              usage: match[3].replace(/\.$/, '').trim()
            });
          }
        } else {
          asset[currentSection] = asset[currentSection] + (asset[currentSection] ? ' ' : '') + trimmed;
        }
      }
    }
  }

  // Формируем sections для старого формата
  asset.sections = [
    { name: 'Описание', content: asset.shortDescription },
    { name: 'Роль/назначение', content: asset.role },
    { name: 'Форма и композиция', content: asset.formAndComposition },
    { name: 'Цвет и материалы', content: asset.colorAndMaterials },
    { name: 'Архитектурные детали', content: asset.architecturalDetails },
    { name: 'Функциональные элементы', content: asset.functionalElements },
    { name: 'Стилистика', content: asset.generalStyle }
  ].filter(function(s) { return s.content; });

} else {
  // Неизвестный формат - берём как есть
  asset.name = 'Unknown_Asset';
  asset.type = 'Ассет';
  asset.sections = [{ name: 'Описание', content: text }];
}

return [{ json: asset }];

const asset = $('Code in JavaScript3').first().json;
const aiPrompt = $input.first().json.message.content;

// Генерируем путь QNAP
const date = new Date().toISOString().split('T')[0].replace(/-/g, '');
const typeFolder = asset.type === 'Иконка' ? 'Icons' : 
                   asset.type === 'Здание' ? 'Buildings' : 'Other';
const qnapPath = '//QNAP/ART/Assets/' + typeFolder + '/' + asset.name + '/';
const fileName = asset.name + '_v001_' + date + '.png';

// Формируем цветовую палитру
let paletteText = '';
if (asset.colorPalette && asset.colorPalette.length > 0) {
  for (let i = 0; i < asset.colorPalette.length; i++) {
    const c = asset.colorPalette[i];
    paletteText = paletteText + '- ' + c.hex + ' (' + c.name + '): ' + c.usage + '\n';
  }
}

// Формируем описание ассета
let assetDescription = '';
if (asset.shortDescription) {
  assetDescription = asset.shortDescription;
} else if (asset.sections && asset.sections.length > 0) {
  assetDescription = asset.sections[0].content || '';
}

// Формируем техническое описание
let technicalDetails = '';
if (asset.formAndComposition) {
  technicalDetails = technicalDetails + '- Форма и композиция: ' + asset.formAndComposition + '\n';
}
if (asset.colorAndMaterials) {
  technicalDetails = technicalDetails + '- Цвет и материалы: ' + asset.colorAndMaterials + '\n';
}
if (asset.architecturalDetails) {
  technicalDetails = technicalDetails + '- Архитектурные детали: ' + asset.architecturalDetails + '\n';
}
if (asset.functionalElements) {
  technicalDetails = technicalDetails + '- Функциональные элементы: ' + asset.functionalElements + '\n';
}

// Формируем description по шаблону ТЕХДОЛГА
const jiraDescription = 'Описание:\n' +
  assetDescription + '\n' +
  (asset.role ? '\n' + asset.role + '\n' : '') +
  '\nПричина появления:\n' +
  'Запрос от GD-отдела. Требуется новый ассет типа "' + asset.type + '".\n' +
  '\nОжидаемый результат:\n' +
  'Готовый ассет "' + asset.name + '" согласно ТЗ:\n' +
  (technicalDetails ? technicalDetails : '') +
  '- Стилистика: semi-realistic casual 3D\n' +
  '- Изометрическая проекция 30°\n' +
  '- Формат: PNG с альфа-каналом\n' +
  '\nШаги воспроизведения:\n' +
  '1. Использовать AI-промт для генерации (см. Необходимые материалы)\n' +
  '2. Проверить соответствие цветовой палитре и ТЗ\n' +
  '3. Сохранить в QNAP по указанному пути\n' +
  '4. Проверить отображение в тестовой сцене\n' +
  '\nКритерии приёмки:\n' +
  '- Соответствие описанию и цветовой палитре\n' +
  '- Изометрическая проекция 30°\n' +
  '- Белый/прозрачный фон\n' +
  '- Качество изображения: высокое, без артефактов\n' +
  '- Стилистика: semi-realistic casual 3D\n' +
  '- Одобрение арт-лида\n' +
  '\nНеобходимые материалы:\n' +
  '\nAI-промт:\n' +
  aiPrompt + '\n' +
  '\nПуть QNAP:\n' +
  qnapPath + fileName + '\n' +
  (paletteText ? '\nЦветовая палитра:\n' + paletteText : '');

return [{
  json: {
    summary: '[ART] ' + asset.name,
    description: jiraDescription,
    assetName: asset.name,
    assetType: asset.type,
    aiPrompt: aiPrompt,
    qnapPath: qnapPath + fileName
  }
}];

